#include <bits/stdc++.h>
using namespace std;

const int N=110,M=2e4+210,INF=0x3f3f3f3f;

int n,m;
int head[N],ver[M],edge[M],nxt[M],tot;
int s,t,d[N],now[N];

void add(int u,int v){
    ver[++tot]=v,edge[tot]=1,nxt[tot]=head[u],head[u]=tot;
    ver[++tot]=u,edge[tot]=0,nxt[tot]=head[v],head[v]=tot;
}

bool bfs(){
    memset(d,0,sizeof(d));
    queue<int> q;
    q.push(s),now[s]=head[s],d[s]=1;
    while(q.size()){
        int x=q.front();
        q.pop();
        for(int i=head[x],y;i;i=nxt[i])
            if(!d[y=ver[i]] && edge[i]){
                d[y]=d[x]+1,now[y]=head[y];
                if(y==t)
                    return 1;
                q.push(y);
            }
    }
    return 0;
}

int Dinic(int x,int flow){
    if(x==t)
        return flow;
    int res=0;
    for(int i=now[x],y;i && res<flow;i=nxt[i]){
        now[x]=i,y=ver[i];
        if(d[y]==d[x]+1 && edge[i]){
            int tmp=Dinic(y,min(edge[i],flow-res));
            if(!tmp)
                d[y]=0;
            edge[i]-=tmp,edge[i^1]+=tmp;
            res+=tmp;
        }
    }
    return res;
}

int main(){
    scanf("%d%d",&m,&n);
    s=n+1,t=n+2;
    tot=1;
    for(int i=1;i<=m;i++)
        add(s,i);
    for(int i=m+1;i<=n;i++)
        add(i,t);
    int u,v;
    while(cin>>u>>v,(~u))
        add(u,v);
    int flow,max_flow=0;
    while(bfs())
        while(flow=Dinic(s,INF))
            max_flow+=flow;
    printf("%d\n",max_flow);
    for(int i=2*n+2;i<=tot;i+=2)
    	if(edge[i^1])
        	printf("%d %d\n",ver[i^1],ver[i]);
    return 0;
}
